var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 우선 자기 소개부터 해 봐.","JPN":"じゃあ、まず自己紹介からして。","ENG":"Then, could you first introduce yourself?","TWN":"那你先自我介紹吧。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"노엘 라이트입니다! 취미는 노래방에서 노래 부르기고, 특기는 요리예요!","JPN":"ノエル・ライトです！　趣味はカラオケで歌うことで、料理が得意です！","ENG":"I'm Noelle Wright! I like to go singing in karaoke! Also, cooking is my specialty!","TWN":"我叫洛艾兒·萊特！興趣是去KTV唱歌，專長是做菜！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"요리?","JPN":"料理？","ENG":"Cooking?","TWN":"做菜？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네. 넷튜브에 영상도 올리고 있어요. 조회수는 낮지만요, 헤헤.","JPN":"はい。ネットチューブに動画もアップしてるんです。再生数は少ないですけど、へへ。","ENG":"Yup! I even upload them on NetTube. But I don't get that many views, he he.","TWN":"是，我還有把做菜的影片PO上網，但瀏覽次數不多，哈哈。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…부모님은?","JPN":"……ご両親は？","ENG":"...What about your parents?","TWN":"…那你爸媽呢？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"두 분 모두 잘 지내고 계세요.","JPN":"二人とも健在です。","ENG":"Both are alive and well.","TWN":"他們還在世，"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"같이 농사를 하시면서 커다란 골든 리트리버도 키우세요.","JPN":"農業をやりながら、大きなゴールデンレトリーバーも飼ってます。","ENG":"They own a farm and raise a massive golden retriever.","TWN":"現在一起種田，還有養一隻黃金獵犬。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이름은 치즈예요. 털이 무척 노랗거든요.","JPN":"名前はチーズっていいます。毛がチーズみたいに黄色いので。","ENG":"His name is Cheese! Because his fur is really yellow.","TWN":"牠叫起司，毛很黃。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 부모님이랑 같이 농사나 짓지, 왜 용병이 되려는 거야?","JPN":"じゃあ、ご両親と一緒に農業をすればいいのに、なんで傭兵になろうとするの？","ENG":"Then shouldn't you be helping your parents out with their farm? Why do you want to be a mercenary?","TWN":"那你為什麼不和他們一起種田，來當什麼傭兵？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펜릴 소대가 너무 좋아서요!","JPN":"フェンリル小隊が大好きなので！","ENG":"Because I like Fenrir Squad a lot!","TWN":"因為我太愛芬里爾小隊了！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"영상을 보고 푹 빠졌어요. 특히 유미나 님이 정말 정말 멋졌거든요.","JPN":"動画を見てハマりました。特にミナ様が本当に本当～にカッコよかったんです。","ENG":"I fell in love with them after watching the video. I thought you were especially cool, Ms. Mina.","TWN":"我看到影片後整個愛了！尤其是劉米娜小姐真的超帥的！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"유미나 님은 제 우상이에요! 물론 힐데 소대장님도! 주시윤 님도!","JPN":"ミナ様は私のアイドルです！　もちろんヒルデ小隊長様も！　シリュウ様も！","ENG":"You're like my role model! Of course, I consider Commander Hilde and Mr. Joo Shiyoon to be role models as well!","TWN":"劉米娜小姐是我的偶像！當然希爾德小隊長也是！周時雲先生也是！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아이 러브 펜릴!","JPN":"アイ・ラブ・フェンリル！","ENG":"I love Fenrir!","TWN":"我愛芬里爾！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"너, 3종 침식체랑 싸워 본 적 있어?","JPN":"あなた、第3種侵食体と戦ってみたことある？","ENG":"Um, have you ever fought a Category 3 C.O. before?","TWN":"我問你，你有對付過3類侵蝕體嗎？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 3종 침식체요?","JPN":"はい？　第3種侵食体ですか？","ENG":"Huh? A Category 3 C.O.?","TWN":"什麼？3類侵蝕體嗎？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그래. 우리 소대는 실력 중시라서.","JPN":"そう。うちの小隊は実力を重視してるから。","ENG":"Yes. Our squad puts skill above all else.","TWN":"對，我們小隊是看能力的。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"3종 침식체와 싸워 본 적도 없다면 받아 줄 수 없어.","JPN":"第3種侵食体と戦ったこともないなら、受け入れてあげられない。","ENG":"If you haven't fought against a Category 3 C.O. before, I don't think we can bring you on board.","TWN":"要是沒有對付過3類侵蝕體的經驗，那是進不來的。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럴 수가!","JPN":"そんな！","ENG":"Oh, no!","TWN":"怎麼這樣！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다른 방법이 없을까요? 기회를 주시면 뭐든 도전해 볼게요!","JPN":"他の方法はないんですか？　機会をくださったら何でも挑戦してみます！","ENG":"Isn't there any other way? If you give me a chance, I'll do anything!","TWN":"沒有其他辦法嗎？只要你們願意給我機會，我什麼都願意挑戰！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 네 실력을 여기서 납득시켜 봐, 노엘.","JPN":"じゃあ、あなたの実力をここで示して。ノエル。","ENG":"Then convince us of your skills, Noelle.","TWN":"那就在這裡用實力說服我們，洛艾兒。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 외에 다른 방법은 없어.","JPN":"それ以外に方法はないよ。","ENG":"That's the only other way.","TWN":"除此以外別無他法。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우, 우으으……!","JPN":"う、ううぅ……！","ENG":"E-ergh...!","TWN":"呃呃呃……！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};